describe("Game of Life - Next Generation", () => {
  it("should return empty grid when given empty grid", () => {
    expect(nextGeneration([])).toEqual([]);
  });
  it("should kill a single cell with no neighbors (underpopulation)", () => {
    expect(nextGeneration([[0, 0]])).toEqual([]);
  });
  it("should kill cells with only one neighbor (underpopulation)", () => {
    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
  });
  it("should keep a cell alive with exactly two neighbors (survival)", () => {
    const result = nextGeneration([[0, 1], [1, 1], [2, 1]]);
    expect(result).toContainEqual([1, 1]);
  });
  it.todo("should keep a cell alive with exactly three neighbors (survival)");
  it.todo("should bring a dead cell to life with exactly three live neighbors (reproduction)");
  it.todo("should kill a cell with more than three neighbors (overpopulation)");
  it.todo("should keep a block pattern stable (still life)");
  it.todo("should oscillate a blinker pattern");
});

const countNeighbors = (x: number, y: number, cells: [number, number][]): number =>
  cells.filter(
    ([cx, cy]) => !(cx === x && cy === y) && Math.abs(cx - x) <= 1 && Math.abs(cy - y) <= 1
  ).length;

export const nextGeneration = (cells: [number, number][]): [number, number][] => {
  return cells.filter(([x, y]) => countNeighbors(x, y, cells) === 2);
};

