export const nextGeneration = (cells: [number, number][]): [number, number][] => {
  const survivors = cells.filter(([x, y]) => {
    const neighborCount = countNeighbors(x, y, cells);
    return neighborCount === 2 || neighborCount === 3;
  });

  const deadCandidates = new Set<string>();
  for (const [x, y] of cells) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        const nx = x + dx;
        const ny = y + dy;
        if (!cells.some(([cx, cy]) => cx === nx && cy === ny)) {
          deadCandidates.add(`${nx},${ny}`);
        }
      }
    }
  }

  const born: [number, number][] = [];
  for (const key of deadCandidates) {
    const [x, y] = key.split(",").map(Number) as [number, number];
    if (countNeighbors(x, y, cells) === 3) {
      born.push([x, y]);
    }
  }

  return [...survivors, ...born];
};

